	@Test
	void lmdbRuleRegistryIncludesScopeRemovalAndExtensionPushdown() {
		RuleRegistry registry = LmdbCascadesRuleProvider.rules(new EvaluationStatistics());

		assertTrue(registry.rules()
				.stream()
				.map(CascadesRule::id)
				.anyMatch("safe-scope-change-removal"::equals),
				"LMDB Cascades registry must include safe scope removal for scoped UNION/Extension rewrites");
		assertTrue(registry.rules()
				.stream()
				.map(CascadesRule::id)
				.anyMatch("join-extension-pushdown"::equals),
				"LMDB Cascades registry must include non-finite prefix pushdown into scoped Extension");
		assertTrue(containsCompiledRule(registry, "filter-values-anchor"),
				"LMDB Cascades registry must include compiled DSL finite-anchor rewrites");
		assertTrue(containsCompiledRule(registry, "safe-scope-change-removal"),
				"LMDB Cascades registry must include compiled DSL scope-removal rewrites");
		assertTrue(containsCompiledRule(registry, "lmdb-access-path-statement-pattern"),
				"LMDB Cascades registry must include compiled DSL statement access-path properties");
		assertTrue(containsCompiledRule(registry, "lmdb-hash-anti-semi-minus"),
				"LMDB Cascades registry must include compiled DSL hash anti-semi child properties");
		assertTrue(containsCompiledRule(registry, "lmdb-remove-unused-optional"),
				"LMDB semantic OPTIONAL elimination must be exposed as a compiled DSL rule");
		assertFalse(containsCompiledRule(registry, "lmdb-distinct-exists-join"),
				"The retired eager GROUP-level EXISTS rewrite must not bypass transparent semi-join implementations");
		assertFalse(containsCompiledRule(registry, "lmdb-finite-filter-values-distinct-rewrite"),
				"The legacy GROUP-level finite-filter owner must not race the reactive memo observer");
		assertTrue(registry.rules()
				.stream()
				.anyMatch(rule -> rule instanceof LmdbDistinctFiniteMembershipRule
						&& LmdbDistinctFiniteMembershipRule.ID.equals(rule.id())),
				"LMDB finite membership DISTINCT rewrites must use the memo-reactive GROUP observer");
		assertTrue(registry.rules()
				.stream()
				.anyMatch(rule -> rule instanceof LmdbDistinctFiniteCodeTypeRule
						&& LmdbDistinctFiniteCodeTypeRule.ID.equals(rule.id())),
				"LMDB code/type DISTINCT rewrites must use the memo-reactive GROUP observer");
		assertTrue(containsCompiledRule(registry, "lmdb-or-filter-values-rewrite"),
				"LMDB OR-to-VALUES rewrites must be exposed as compiled DSL rules");
		assertTrue(containsCompiledRule(registry, "lmdb-or-filter-union-rewrite"),
				"LMDB duplicate-insensitive OR-to-UNION rewrites must be exposed as compiled DSL rules");
	}

	@Test
	void statementPatternPlanningEstimateUsesPlanningCardinalityPath() throws IOException {
		ValueStore valueStore = mock(ValueStore.class);
		TripleStore tripleStore = mock(TripleStore.class);
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		org.eclipse.rdf4j.model.IRI subject = vf.createIRI("urn:test:s");
		org.eclipse.rdf4j.model.IRI predicate = vf.createIRI("urn:test:p");
		org.eclipse.rdf4j.model.IRI object = vf.createIRI("urn:test:o");
		StatementPattern pattern = new StatementPattern(new Var("s", subject), new Var("p", predicate),
				new Var("o", object));
		when(valueStore.getId(subject)).thenReturn(1L);
		when(valueStore.getId(predicate)).thenReturn(2L);
		when(valueStore.getId(object)).thenReturn(3L);
		when(tripleStore.getDataRevision()).thenReturn(7L);
		when(tripleStore.planningCardinality(1L, 2L, 3L, LmdbValue.UNKNOWN_ID)).thenReturn(42.0d);
		when(tripleStore.cardinality(1L, 2L, 3L, LmdbValue.UNKNOWN_ID)).thenReturn(99.0d);

		LmdbStatementPatternCardinalitySource source = new LmdbStatementPatternCardinalitySource(valueStore,
				tripleStore);

		assertEquals(42.0d, source.estimateForPlanning(pattern));
		verify(tripleStore).planningCardinality(1L, 2L, 3L, LmdbValue.UNKNOWN_ID);
		verify(tripleStore, never()).cardinality(1L, 2L, 3L, LmdbValue.UNKNOWN_ID);
	}

	@Test
	void statementPatternPlanningDefersRepeatedVariableExactScan() throws IOException {
		ValueStore valueStore = mock(ValueStore.class);
		TripleStore tripleStore = mock(TripleStore.class);
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		org.eclipse.rdf4j.model.IRI predicate = vf.createIRI("urn:test:p");
		StatementPattern pattern = new StatementPattern(new Var("node"), new Var("p", predicate), new Var("node"));
		int repeatedPairMask = TripleStore.repeatedComponentPairMask(TripleStore.SUBJ_IDX, TripleStore.OBJ_IDX);
		when(valueStore.getId(predicate)).thenReturn(2L);
		when(tripleStore.getDataRevision()).thenReturn(7L);
		when(tripleStore.repeatedVariableCardinality(LmdbValue.UNKNOWN_ID, 2L, LmdbValue.UNKNOWN_ID,
				LmdbValue.UNKNOWN_ID, repeatedPairMask)).thenReturn(3.0d);
		when(tripleStore.planningCardinality(LmdbValue.UNKNOWN_ID, 2L, LmdbValue.UNKNOWN_ID,
				LmdbValue.UNKNOWN_ID)).thenReturn(42.0d);

		LmdbStatementPatternCardinalitySource source = new LmdbStatementPatternCardinalitySource(valueStore,
				tripleStore);

		assertEquals(42.0d, source.estimateForPlanning(pattern));
		verify(tripleStore).planningCardinality(LmdbValue.UNKNOWN_ID, 2L, LmdbValue.UNKNOWN_ID,
				LmdbValue.UNKNOWN_ID);
		verify(tripleStore, never()).repeatedVariableCardinality(LmdbValue.UNKNOWN_ID, 2L, LmdbValue.UNKNOWN_ID,
				LmdbValue.UNKNOWN_ID, repeatedPairMask);

		assertEquals(3.0d, source.estimateExact(pattern));
		verify(tripleStore).repeatedVariableCardinality(LmdbValue.UNKNOWN_ID, 2L, LmdbValue.UNKNOWN_ID,
				LmdbValue.UNKNOWN_ID, repeatedPairMask);
	}

