	@Test
	void optionalAnchoredLookupKeepsChildWinnersVisible() {
		CascadesRule rule = LmdbCascadesRuleProvider.rules(new RecordingStatistics())
				.rules()
				.stream()
				.filter(candidate -> "lmdb-optional-rhs-anchored-lookup".equals(candidate.id()))
				.findFirst()
				.orElseThrow();
		LeftJoin optional = new LeftJoin(new StatementPattern(new Var("person"), new Var("memberOf"), new Var("org")),
				new StatementPattern(new Var("org"), new Var("label"), new Var("orgName")));
		MemoExpr expression = new MemoExpr(1, 7, "LeftJoin", List.of(), "", optional, PhysicalProperties.ANY,
				RuleKind.TRANSFORMATION, CostVector.ZERO, List.of(), null);

		RuleApplication application = rule.apply(expression, OptimizationGoal.root(),
				new RuleContext(null, null, null, null)).getFirst();

		assertFalse(application.opaque(),
				"Optional anchored lookup is a costed RDF4J LeftJoin alternative, not a separate executable subtree; "
						+ "Cascades must still plan and install child winners");
		assertEquals("lmdb-optional-anchor-decomposed", application.metadata());
	}

	@Test
	void materializedMinusAntiSemiRetainsInputsAndDeclaresOnlyLocalWork() {
		MaterializedExistsWorkStatistics statistics = new MaterializedExistsWorkStatistics();
		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		CascadesRule rule = LmdbCascadesRuleProvider.rules(statistics)
				.rules()
				.stream()
				.filter(candidate -> "lmdb-materialized-minus-anti-semi".equals(candidate.id()))
				.findFirst()
				.orElseThrow();
		Difference minus = new Difference(pattern("a", "follows", "b"), pattern("a", "name", "optName"));
		int groupId = memo.intern(minus);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();

		RuleApplication application = rule.apply(expression, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null)).getFirst();
		MemoExpr physical = addPhysicalAlternative(memo, application);
		List<Winner> selectedChildren = List.of(
				winner(memo, physical.inputGroupIds().get(0), 5.0d, 100.0d),
				winner(memo, physical.inputGroupIds().get(1), 3.0d, 80.0d,
						PhysicalProperties.Materialization.MATERIALIZED));
		CostVector localCost = costModel.localCost(physical, OptimizationGoal.root(), selectedChildren);
		PhysicalProperties delivered = costModel.deliveredProperties(physical, OptimizationGoal.root(),
				selectedChildren);
		double composedWorkRows = selectedChildren.stream().mapToDouble(winner -> winner.cost().workRows()).sum()
				+ localCost.workRows();

		assertAll(
				() -> assertEquals("lmdb-materialized-minus-anti-semi", application.metadata()),
				() -> assertFalse(application.opaque(),
						"Materialized MINUS must keep both child groups visible to Cascades"),
				() -> assertEquals(expression.inputGroupIds(), physical.inputGroupIds(),
						"The physical MINUS alternative must retain its left and right memo inputs"),
				() -> assertEquals(2, physical.inputGroupIds().size()),
				() -> assertEquals(PhysicalProperties.Materialization.MATERIALIZED,
						physical.inputs().get(1).requiredProperties().materialization(),
						"The MINUS RHS cache is an executable child requirement"),
				() -> assertEquals(CostVector.ZERO, application.localCost(),
						"The rule must declare structure; selected children determine local work during costing"),
				() -> assertEquals(8.0d, localCost.workRows(), 0.0d,
						"MINUS local work is selected RHS-cache build plus selected left-side probes"),
				() -> assertTrue(costModel.locallyCostedInputIndexes(physical, OptimizationGoal.root(),
						selectedChildren).isEmpty(), "Both selected child totals must remain planner-owned"),
				() -> assertEquals(188.0d, composedWorkRows, 0.0d,
						"Planner composition must add both child totals and local build/probe exactly once"),
				() -> assertEquals(PhysicalProperties.Materialization.ANY,
						application.deliveredProperties().materialization(),
						"Only the MINUS RHS is cached; the parent output remains streaming"),
				() -> assertEquals(PhysicalProperties.Materialization.ANY, delivered.materialization(),
						"A materialized right child must not leak its cache property to the MINUS output"));
	}

	@Test
	void compiledHashAntiSemiRetainsMaterializedRhsAndUsesCanonicalLocalCost() {
		MaterializedExistsWorkStatistics statistics = new MaterializedExistsWorkStatistics();
		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		CascadesRule rule = LmdbCascadesRuleProvider.rules(statistics)
				.rules()
				.stream()
				.filter(candidate -> "lmdb-hash-anti-semi-minus".equals(candidate.id()))
				.findFirst()
				.orElseThrow();
		Difference minus = new Difference(pattern("a", "follows", "b"), pattern("a", "name", "optName"));
		int groupId = memo.intern(minus);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();

		RuleApplication application = rule.apply(expression, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null)).getFirst();
		MemoExpr physical = addPhysicalAlternative(memo, application);
		List<Winner> selectedChildren = List.of(
				winner(memo, physical.inputGroupIds().get(0), 5.0d, 100.0d),
				winner(memo, physical.inputGroupIds().get(1), 3.0d, 80.0d,
						PhysicalProperties.Materialization.MATERIALIZED));
		CostVector localCost = costModel.localCost(physical, OptimizationGoal.root(), selectedChildren);
		double composedWorkRows = selectedChildren.stream().mapToDouble(winner -> winner.cost().workRows()).sum()
				+ localCost.workRows();

		assertAll(
				() -> assertFalse(application.opaque()),
				() -> assertEquals("lmdb:hash-anti-semi", application.deliveredProperties().accessPath()),
				() -> assertEquals(PhysicalProperties.Materialization.STREAMING,
						application.inputRequirements().get(0).materialization()),
				() -> assertEquals(PhysicalProperties.Materialization.MATERIALIZED,
						application.inputRequirements().get(1).materialization()),
				() -> assertEquals(PhysicalProperties.Materialization.MATERIALIZED,
						physical.inputs().get(1).requiredProperties().materialization()),
				() -> assertEquals(8.0d, localCost.workRows(), 0.0d,
						"Canonical anti-semi local work is RHS build rows plus left probe rows"),
				() -> assertTrue(costModel.locallyCostedInputIndexes(physical, OptimizationGoal.root(),
						selectedChildren).isEmpty(), "Both selected child totals must remain planner-owned"),
				() -> assertEquals(188.0d, composedWorkRows, 0.0d,
						"Planner composition must add child totals and local build/probe work exactly once"));
	}

	@Test
	void materializedMinusAntiSemiDoesNotRequireOuterInputBindings() {
		CascadesRule rule = LmdbCascadesRuleProvider.rules(new RecordingStatistics())
				.rules()
				.stream()
				.filter(candidate -> "lmdb-materialized-minus-anti-semi".equals(candidate.id()))
				.findFirst()
				.orElseThrow();
		Difference minus = new Difference(pattern(), pattern());
		MemoExpr expression = new MemoExpr(1, 7, "Difference", List.of(), "", minus, PhysicalProperties.ANY,
				RuleKind.TRANSFORMATION, CostVector.ZERO, List.of(), null);
		OptimizationGoal goal = OptimizationGoal.root()
				.withRequiredProperties(PhysicalProperties.builder().boundVars(Set.of("s")).build());

		RuleApplication application = rule.apply(expression, goal, new RuleContext(null, null, null, null))
				.getFirst();

		assertTrue(application.deliveredProperties().inputBoundVars().isEmpty(),
				"A materialized MINUS RHS cache is built once for the plan and must not require outer bindings: "
						+ application.deliveredProperties());
	}

	@Test
	void materializedMinusPlannerAdmissionDoesNotInheritCorrelatedRhsInputBindings() {
		SubjectLookupStatistics statistics = new SubjectLookupStatistics();
		Difference minus = new Difference(
				new StatementPattern(new Var("med"), new Var("code"), new Var("codeValue")),
				new Filter(new StatementPattern(new Var("med"), new Var("dosage"), new Var("dose")),
						new Bound(new Var("dose"))));
		CascadesTelemetry.Recording telemetry = new CascadesTelemetry.Recording(1024);

		new org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.CascadesPlanner(
				CascadesCostModel.from(statistics), LmdbCascadesRuleProvider.rules(statistics), telemetry)
						.optimize(minus, OptimizationGoal.root(minus, PhysicalProperties.ANY));

		String trace = String.join("\n", telemetry.trace());
		assertTrue(trace.contains("rule=lmdb-materialized-minus-anti-semi"), trace);
		assertFalse(trace.contains("rule=lmdb-materialized-minus-anti-semi reason=missing-physical-property"),
				trace);
		assertTrue(trace.contains("costed group=") && trace.contains("rule=lmdb-materialized-minus-anti-semi"),
				trace);
	}

	@Test
	void materializedExistsSemiRetainsInputsAndDeclaresOnlyLocalWork() {
		MaterializedExistsWorkStatistics statistics = new MaterializedExistsWorkStatistics();
		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		CascadesRule rule = LmdbCascadesRuleProvider.rules(statistics)
				.rules()
				.stream()
				.filter(candidate -> "lmdb-materialized-exists-semi".equals(candidate.id()))
				.findFirst()
				.orElseThrow();
		Filter existsFilter = new Filter(pattern("a", "follows", "b"),
				new Exists(pattern("a", "name", "optName")));
		int groupId = memo.intern(existsFilter);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();

		RuleApplication application = rule.apply(expression, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null)).getFirst();
		MemoExpr physical = addPhysicalAlternative(memo, application);
		List<Winner> selectedChildren = List.of(
				winner(memo, physical.inputGroupIds().get(0), 5.0d, 100.0d),
				winner(memo, physical.inputGroupIds().get(1), 3.0d, 80.0d,
						PhysicalProperties.Materialization.MATERIALIZED));
		CostVector localCost = costModel.localCost(physical, OptimizationGoal.root(), selectedChildren);
		PhysicalProperties delivered = costModel.deliveredProperties(physical, OptimizationGoal.root(),
				selectedChildren);
		double composedWorkRows = selectedChildren.stream().mapToDouble(winner -> winner.cost().workRows()).sum()
				+ localCost.workRows();

		assertAll(
				() -> assertEquals("lmdb-materialized-exists-semi", application.metadata()),
				() -> assertEquals("materialized-exists-semi",
						application.alternative().getStringMetricPlanned("optimizer.filterAlgorithmHint"),
						"The executable filter must opt in to the materialized EXISTS implementation"),
				() -> assertFalse(application.opaque(),
						"Materialized EXISTS must keep its outer and scalar-subquery groups visible to Cascades"),
				() -> assertEquals(expression.inputGroupIds(), physical.inputGroupIds(),
						"The physical EXISTS alternative must retain both outer and scalar-subquery memo inputs"),
				() -> assertEquals(2, physical.inputGroupIds().size()),
				() -> assertEquals(PhysicalProperties.Materialization.MATERIALIZED,
						physical.inputs().get(1).requiredProperties().materialization(),
						"The EXISTS RHS cache is an executable scalar-subquery requirement"),
				() -> assertEquals(SemanticScope.SET, physical.inputs().get(1).requiredSemanticScope(),
						"A correlated materialized EXISTS must retain every distinct shared RHS key"),
				() -> assertEquals(CostVector.ZERO, application.localCost(),
						"The rule must declare structure; selected children determine local work during costing"),
				() -> assertEquals(8.0d, localCost.workRows(), 0.0d,
						"EXISTS local work is selected RHS-cache build plus selected left-side probes"),
				() -> assertTrue(costModel.locallyCostedInputIndexes(physical, OptimizationGoal.root(),
						selectedChildren).isEmpty(), "Scalar RHS execution must remain planner-owned"),
				() -> assertEquals(188.0d, composedWorkRows, 0.0d,
						"Planner composition must add both child totals and local build/probe exactly once"),
				() -> assertEquals(PhysicalProperties.Materialization.ANY,
						application.deliveredProperties().materialization(),
						"Only the EXISTS RHS is cached; the parent output remains streaming"),
				() -> assertEquals(PhysicalProperties.Materialization.ANY, delivered.materialization(),
						"A materialized scalar child must not leak its cache property to the FILTER output"),
				() -> assertEquals("materializedExists", application.deliveredProperties().accessPath()));
	}

