	@Test
	void cascadesTraceRecordsConsideredCostedAcceptedAndDiscardedPlans() {
		CascadesTelemetry.Recording telemetry = new CascadesTelemetry.Recording(64);
		CascadesRule twoAlternativeRule = new CascadesRule() {

			@Override
			public String id() {
				return "test-two-alternatives";
			}

			@Override
			public RuleKind kind() {
				return RuleKind.IMPLEMENTATION;
			}

			@Override
			public RuleDescriptor descriptor() {
				return RuleDescriptor.builder(id(), kind())
						.rootOperators(RuleRootOperator.STATEMENT_PATTERN)
						.wakeUpEvents(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED)
						.convergenceClass(RuleConvergenceClass.FINITE_EQUIVALENCE_EXPANSION)
						.build();
			}

			@Override
			public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
				return expression.logical();
			}

			@Override
			public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
				return 100;
			}

			@Override
			public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
				return List.of(
						RuleApplication.physical(expression.groupId(), pattern(), PhysicalProperties.ANY,
								CostVector.ofRowsAndWork(1.0d, 1.0d, QErrorInterval.exact(1.0d, "test")),
								null, "cheap"),
						RuleApplication.physical(expression.groupId(), pattern(), PhysicalProperties.ANY,
								CostVector.ofRowsAndWork(10.0d, 10.0d, QErrorInterval.exact(10.0d, "test")),
								null, "expensive"));
			}
		};

		new org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.CascadesPlanner(
				CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.builder().add(twoAlternativeRule).build(), telemetry)
						.optimize(pattern(), OptimizationGoal.root());

		String trace = String.join("\n", telemetry.trace());
		assertTrue(trace.contains("consider group="), trace);
		assertTrue(trace.contains("costed group="), trace);
		assertTrue(trace.contains("accepted group="), trace);
		assertTrue(trace.contains("discard group="), trace);
		assertTrue(trace.contains("rule=test-two-alternatives"), trace);
		assertTrue(trace.contains("metadata=cheap"), trace);
		assertTrue(trace.contains("metadata=expensive"), trace);
		assertTrue(trace.contains("cost=CostVector"), trace);
		assertTrue(trace.contains("plan=StatementPattern"), trace);
	}

