	@Test
	void genericImplementationDefersMinusWithAssuredJoinPrefix() {
		StatementPattern codeLookup = pattern("med", "code", "code");
		StatementPattern typeGuard = pattern("med", "type", "Medication");
		Filter leftWithExists = new Filter(new Join(codeLookup, typeGuard),
				new Exists(pattern("patient", "hasMedication", "med")));
		Difference difference = new Difference(leftWithExists,
				new Filter(pattern("med", "dosage", "dose"), new Bound(new Var("dose"))));

		assertFalse(LmdbJoinIslandConnectivity.genericImplementationAllowed(difference, true, false),
				"Generic RDF4J Difference must not finalize a MINUS while the logical prefix rewrite can evaluate "
						+ "it against an assured selective join prefix first");
	}

	@Test
	void genericImplementationDefersAnchorableFiniteFilter() {
		Filter codeIn = new Filter(pattern("med", "code", "code"), listMember("code", "MED-1000", "MED-1001"));

		assertFalse(LmdbJoinIslandConnectivity.genericImplementationAllowed(codeIn, true, false),
				"Generic RDF4J Filter must not materialize a finite IN filter while LMDB can expose it as a cheaper "
						+ "VALUES anchor");
	}

	@Test
	void genericImplementationAllowsWrappersOverAnchorableFiniteFilter() {
		Filter codeIn = new Filter(pattern("med", "code", "code"), listMember("code", "MED-1000", "MED-1001"));
		ProjectionElemList projectionElems = new ProjectionElemList();
		projectionElems.addElement(new ProjectionElem("med"));
		Projection projection = new Projection(codeIn.clone(), projectionElems);
		Group group = new Group(codeIn.clone());

		assertTrue(LmdbJoinIslandConnectivity.genericImplementationAllowed(projection, true, false),
				"Generic Projection should remain legal so its child finite filter can still be implemented by LMDB");
		assertTrue(LmdbJoinIslandConnectivity.genericImplementationAllowed(group, true, false),
				"Generic Group should remain legal so its child finite filter can still be implemented by LMDB");
	}

	@Test
	void connectedProviderDoesNotOwnScopedUnionSeparatorFactor() {
		TupleExpr deepPrefix = new Join(
				new Join(new StatementPattern(new Var("person"), new Var("memberOf"), new Var("org")),
						new StatementPattern(new Var("org"), new Var("department"), new Var("department"))),
				new StatementPattern(new Var("department"), new Var("makesOffer"), new Var("offer")));
		TupleExpr pageAndFanout = new Join(
				new StatementPattern(new Var("topic"), new Var("mainEntityOfPage"), new Var("page")),
				scopedFanoutUnion());
		TupleExpr root = new Join(new Join(deepPrefix,
				new StatementPattern(new Var("offer"), new Var("itemOffered"), new Var("work"))),
				new Join(new StatementPattern(new Var("work"), new Var("about"), new Var("topic")), pageAndFanout));

		assertFalse(LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(root),
				"The connected hypergraph provider must not treat a scoped UNION separator join as an opaque "
						+ "costed factor; otherwise the selected candidate can be only partially planned");
	}

	@Test
	@SuppressWarnings({ "rawtypes", "unchecked" })
	void legacyCompareAliasUsesFallbackWithoutSyntheticCostArbitration() throws Exception {
		LmdbCascadesOptimizer optimizer = new LmdbCascadesOptimizer(new RecordingStatistics(), false);
		Class<?> modeClass = Class.forName(LmdbCascadesOptimizer.class.getName() + "$Mode");
		Class<?> policyClass = Class.forName(LmdbCascadesOptimizer.class.getName() + "$StandardPlanPolicy");
		Class<?> candidateClass = Class.forName(LmdbCascadesOptimizer.class.getName() + "$StandardPlanCandidate");
		Object autoMode = Enum.valueOf((Class<Enum>) modeClass.asSubclass(Enum.class), "AUTO");
		Object fallbackPolicy = legacyStandardPlanPolicy("compare");
		assertEquals("FALLBACK", ((Enum<?>) fallbackPolicy).name());
		Constructor<?> candidateConstructor = candidateClass
				.getDeclaredConstructor(LmdbCascadesOptimizer.class, TupleExpr.class, String.class);
		candidateConstructor.setAccessible(true);
		StatementPattern standardRoot = pattern();
		standardRoot.setCardinality(1.0d);
		Object standardPlan = candidateConstructor.newInstance(optimizer, standardRoot, "test-standard");
		MemoExpr expression = new MemoExpr(1, 1, "StatementPattern", List.of(), "", pattern(),
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);
		Winner winner = new Winner(expression, pattern(), PhysicalProperties.ANY,
				CostVector.ofRowsAndWork(1.0d, 10_000.0d, QErrorInterval.exact(1.0d, "test-cascades")),
				List.of(), false, "complete");
		CascadesPlan cascadesPlan = new CascadesPlan(new Memo(CascadesCostModel.from(new RecordingStatistics())),
				1, OptimizationGoal.root(), Optional.of(winner), false, List.of("complete"));
		Method standardPlanWins = LmdbCascadesOptimizer.class.getDeclaredMethod("standardPlanWins", modeClass,
				policyClass, candidateClass, CascadesPlan.class);
		standardPlanWins.setAccessible(true);

		assertFalse((Boolean) standardPlanWins.invoke(optimizer, autoMode, fallbackPolicy, standardPlan,
				cascadesPlan),
				"Legacy compare is only a no-winner fallback alias and must not replace Cascades from an "
						+ "uncalibrated synthetic standard-plan cost");
	}

