	@Test
	void opaqueJoinOrderWinnerAnnotatesMaterializedPlanWithoutFallbackNoWinner() {
		RecordingJoinOrderStatistics statistics = new RecordingJoinOrderStatistics();
		QueryRoot root = new QueryRoot(leftDeepJoin(4));

		new LmdbCascadesOptimizer(statistics, false).optimize(root, null, EmptyBindingSet.getInstance());
		LmdbCascadesExplainFinalizer.INSTANCE.optimize(root, null, EmptyBindingSet.getInstance());

		List<String> fallbackNodes = new ArrayList<>();
		root.visit(new org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(org.eclipse.rdf4j.query.algebra.QueryModelNode node) {
				if (node instanceof TupleExpr tupleExpr
						&& "fallback_no_winner".equals(tupleExpr.getStringMetricPlanned(
								TelemetryMetricNames.PLANNED_ESTIMATE_USAGE))) {
					fallbackNodes.add(tupleExpr.getClass().getSimpleName() + ":" + tupleExpr.getSignature());
				}
				node.visitChildren(this);
			}
		});

		assertTrue(fallbackNodes.isEmpty(), fallbackNodes.toString());
	}

	@Test
	void rootReplacementKeepsReplacementOperatorWhenRootHasNoParent() throws Exception {
		QueryRoot root = new QueryRoot(new Difference(pattern(), pattern()));
		Filter replacement = new Filter(pattern(), new Not(new Exists(pattern())));
		LmdbCascadesOptimizer optimizer = new LmdbCascadesOptimizer(new RecordingStatistics(), false);
		Method replaceRootIfSafe = LmdbCascadesOptimizer.class.getDeclaredMethod("replaceRootIfSafe",
				TupleExpr.class, TupleExpr.class);
		replaceRootIfSafe.setAccessible(true);

		replaceRootIfSafe.invoke(optimizer, root, replacement);

		assertTrue(root.getArg() instanceof Filter, root.toString());
	}

	private static StatementPattern pattern() {
		return new StatementPattern(new Var("s"), new Var("p"), new Var("o"));
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private static ListMemberOperator listMember(String name, String... values) {
		ListMemberOperator operator = new ListMemberOperator();
		operator.addArgument(new Var(name));
		for (String value : values) {
			operator.addArgument(new ValueConstant(SimpleValueFactory.getInstance().createLiteral(value)));
		}
		return operator;
	}

	private static LeftJoin sparseQ6OptionalShape() {
		TupleExpr deepPath = new Join(
				new Join(
						new Join(
								new Join(new StatementPattern(new Var("person"), iri("a"), iri("Person")),
										new StatementPattern(new Var("person"), iri("memberOf"), new Var("org"))),
								new StatementPattern(new Var("org"), iri("department"), new Var("department"))),
						new StatementPattern(new Var("department"), iri("makesOffer"), new Var("offer"))),
				new Join(
						new Join(new StatementPattern(new Var("offer"), iri("itemOffered"), new Var("work")),
								new StatementPattern(new Var("work"), iri("about"), new Var("topic"))),
						new StatementPattern(new Var("topic"), iri("mainEntityOfPage"), new Var("page"))));
		Union scopedUnion = new Union(new StatementPattern(new Var("work"), iri("review"), new Var("review")),
				new StatementPattern(new Var("page"), iri("event"), new Var("event")));
		scopedUnion.setVariableScopeChange(true);
		return new LeftJoin(new Join(deepPath, scopedUnion),
				new StatementPattern(new Var("org"), iri("employee"), new Var("optEmployee")));
	}

	private static Var iri(String name) {
		return new Var("_const_" + name, SimpleValueFactory.getInstance().createIRI("urn:test:" + name));
	}

	@SuppressWarnings("unchecked")
	private static void collectSubtreeCandidates(TupleExpr root, List<Object> candidates) throws Exception {
		Class<?> collectorClass = Class.forName(
				LmdbCascadesOptimizer.class.getName() + "$ContextualSubtreeCandidateCollector");
		Constructor<?> constructor = collectorClass.getDeclaredConstructor(TupleExpr.class, Set.class, List.class);
		constructor.setAccessible(true);
		Object collector = constructor.newInstance(root, Set.of(), candidates);
		root.visit((QueryModelVisitor<RuntimeException>) collector);
	}

	@SuppressWarnings("unchecked")
	private static void collectConditionSubqueryCandidates(TupleExpr root, List<Object> candidates) throws Exception {
		Class<?> collectorClass = Class.forName(
				LmdbCascadesOptimizer.class.getName() + "$ConditionSubqueryCandidateCollector");
		Constructor<?> constructor = collectorClass.getDeclaredConstructor(TupleExpr.class, Set.class, List.class);
		constructor.setAccessible(true);
		Object collector = constructor.newInstance(root, Set.of(), candidates);
		root.visit((QueryModelVisitor<RuntimeException>) collector);
	}

	private static TupleExpr candidateTupleExpr(Object candidate) {
		try {
			Method method = candidate.getClass().getDeclaredMethod("tupleExpr");
			method.setAccessible(true);
			return (TupleExpr) method.invoke(candidate);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError(e);
		}
	}

	@SuppressWarnings("unchecked")
	private static Set<String> candidateBoundVars(Object candidate) {
		try {
			Method method = candidate.getClass().getDeclaredMethod("boundVars");
			method.setAccessible(true);
			return (Set<String>) method.invoke(candidate);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError(e);
		}
	}

	private static TupleExpr leftDeepJoin(int factors) {
		TupleExpr root = pattern();
		for (int i = 1; i < factors; i++) {
			root = new Join(root, pattern());
		}
		return root;
	}

	private static TupleExpr connectedChainJoin(int factors) {
		TupleExpr root = chainPattern(0);
		for (int i = 1; i < factors; i++) {
			root = new Join(root, chainPattern(i));
		}
		return root;
	}

	private static StatementPattern chainPattern(int index) {
		return new StatementPattern(new Var("v" + index),
				new Var("p" + index, SimpleValueFactory.getInstance().createIRI("urn:test:p" + index)),
				new Var("v" + (index + 1)));
	}

