			return Optional.of(new FactorCostEstimate(50.0d, 10.0d,
					Map.of(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE, "directLookup"), robustMetrics(), true, true,
					0, 0, 12.0d));
